member.example:
Set a boolean Animator parameter using a serialized binder field — the target Animator is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AnimatorSetBoolBinder _isRunning;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isRunning;
    }


Set a boolean Animator parameter by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Animator _animator;
        
        private AnimatorSetBoolBinder IsRunning =>
            new(_animator, "IsRunning");
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isRunning;
    }

